import os
import tensorflow as tf
from tensorflow import keras
import boto3
from botocore.client import Config

# Configure aws credentials
ACCESS_KEY_ID = os.getenv("ACCESS_KEY_ID")
ACCESS_SECRET_KEY = os.getenv("ACCESS_SECRET_KEY")
BUCKET_NAME = os.getenv('MODEL_BUCKET_NAME')
MODEL_PATH = os.getenv('MODEL_PATH')

# Initialize s3 client
s3 = boto3.resource(
    's3',
    aws_access_key_id=ACCESS_KEY_ID,
    aws_secret_access_key=ACCESS_SECRET_KEY,
    config=Config(signature_version='s3v4')
)

def get_latest_model_version():
    max_version = 0
    models = s3.Bucket(BUCKET_NAME).objects.filter(Prefix=MODEL_PATH)
    for model in models:
        version = int(model.key.split("/")[-1])
        if version > max_version:
            max_version = version
    return max_version

def load_model_from_s3(bucket_name, model_path, version):
    download_path = f"/tmp/model_{version}"
    s3.Bucket(bucket_name).download_file(f"{model_path}/{version}", download_path)
    return keras.models.load_model(download_path)

def main():
    latest_model_version = get_latest_model_version()
    model = load_model_from_s3(BUCKET_NAME, MODEL_PATH, latest_model_version)

if __name__ == "__main__":
    main()